action.new_str:
void
EmitIR::operator()(Decl* obj)
{
  // TODO: 添加变量声明处理的跳转

  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);

  if (auto p = obj->dcst<VarDecl>())
    return self(p);

  ABORT();
}

void
EmitIR::operator()(VarDecl* obj)
{
  auto& irb = *mCurIrb;

  if (mCurFunc == nullptr) {
    // Global variable
    llvm::Constant* init = nullptr;
    if (obj->init)
      init = llvm::dyn_cast<llvm::Constant>(self(obj->init));

    auto global = new llvm::GlobalVariable(
      mMod, 
      self(obj->type), 
      obj->type->qual.const_, 
      llvm::GlobalValue::ExternalLinkage, 
      init, 
      obj->name
    );
    obj->any = global;
  } else {
    // Local variable
    auto alloca = irb.CreateAlloca(self(obj->type), nullptr, obj->name);
    obj->any = alloca;

    if (obj->init) {
      auto initVal = self(obj->init);
      irb.CreateStore(initVal, alloca);
    }
  }
}

